function __middleware(req) {
  const h = req.headers || {};
  return { auth: String(h["authorization"]||"").toLowerCase(), n: 2000 };
}

globalThis.handleRequest = function (req) {
  const m = __middleware(req);
  return {
    status: 200,
    body: JSON.stringify({ ok: true, path: req.path, m }),
    contentType: "application/json",
  };
};
